// Transform parameters for visual layout (viewBox "0 0 220 125")
const MAINLAND_DX = -140;
const MAINLAND_DY = -140;
const AK_SCALE = 0.22;
const AK_DX = 5;
const AK_DY = 95;
const HI_DX = 40;
const HI_DY = -132;

// Map a state's source-SVG center to its on-screen (viewBox) coords after layout transforms
function displayCenter(abbr: string): [number, number] | null {
  const entry = S[abbr];
  if (!entry) return null;
  const [, cx, cy] = entry;
  if (abbr === "AK") return [AK_DX + cx * AK_SCALE, AK_DY + cy * AK_SCALE];
  if (abbr === "HI") return [HI_DX + cx, HI_DY + cy];
  return [cx + MAINLAND_DX, cy + MAINLAND_DY];
}

export default function USMap() {
  const [hovered, setHovered] = useState<string | null>(null);
  const [selected, setSelected] = useState<string | null>(null);
  const [peOnlyAbbrs, setPeOnlyAbbrs] = useState<string[]>(DEFAULT_PE);
  const [seOnlyAbbrs, setSeOnlyAbbrs] = useState<string[]>(DEFAULT_SE);
  const [peSeAbbrs, setPeSeAbbrs] = useState<string[]>(DEFAULT_PESE);

  // Load licensed-jurisdiction config from Firestore (editable at /admin/jurisdictions).
  useEffect(() => {
    const load = async () => {
      try {
        const snap = await getDoc(doc(db, "settings", "jurisdictions"));
        if (snap.exists()) {
          const d = snap.data() as { peOnly?: string[]; seOnly?: string[]; peSe?: string[] };
          if (Array.isArray(d.peOnly)) setPeOnlyAbbrs(d.peOnly);
          if (Array.isArray(d.seOnly)) setSeOnlyAbbrs(d.seOnly);
          if (Array.isArray(d.peSe)) setPeSeAbbrs(d.peSe);
        }
      } catch (err) {
        console.error("Failed to load jurisdictions config:", err);
      }
    };
    load();
  }, []);

  const active = selected || hovered;

  const lt = (a: string): LT => {
    if (peSeAbbrs.includes(a)) return "pese";
    if (peOnlyAbbrs.includes(a)) return "pe";
    if (seOnlyAbbrs.includes(a)) return "se";
    return "none";
  };

  // Names for the three-column jurisdiction list, derived from the live arrays.
  const peOnlyNames = peOnlyAbbrs.map(a => abbrToName[a]).filter(Boolean);
  const seOnlyNames = seOnlyAbbrs.map(a => abbrToName[a]).filter(Boolean);
  const peSeNames = peSeAbbrs.map(a => abbrToName[a]).filter(Boolean);

  const fill = (a: string) => {
    const t = lt(a);
    return active === a ? C[t][1] : C[t][0];
  };

  const handleHoverName = useCallback((name: string) => {
    setHovered(nameToAbbr[name] || null);
  }, []);
  const handleLeaveName = useCallback(() => setHovered(null), []);
  const handleClickName = useCallback((name: string) => {
    const a = nameToAbbr[name];
    if (a) setSelected(prev => prev === a ? null : a);
  }, []);
  const isActive = (name: string) => nameToAbbr[name] === active;

  const tooltipState = active && lt(active) !== "none" ? active : null;
  const tooltipName = tooltipState ? abbrToName[tooltipState] : null;
  const tooltipCenter = tooltipState && tooltipState !== "VI" ? displayCenter(tooltipState) : null;

  const renderPath = (abbr: string) => {
    const entry = S[abbr];
    if (!entry) return null;
    const [d] = entry;
    const type = lt(abbr);
    const isLicensed = type !== "none";
    return (
      <path
        key={abbr}
        d={d}
        fill={fill(abbr)}
        stroke="none"
        className={isLicensed ? "transition-colors duration-200 cursor-pointer" : ""}
        style={isLicensed ? undefined : { pointerEvents: "none" }}
        onMouseEnter={isLicensed ? () => setHovered(abbr) : undefined}
        onMouseLeave={isLicensed ? () => setHovered(null) : undefined}
        onClick={isLicensed ? () => setSelected(p => p === abbr ? null : abbr) : undefined}
      />
    );
  };

  const mainlandAbbrs = Object.keys(S).filter(a => a !== "AK" && a !== "HI");

  return (
    <div>
      <div className="bg-gray-100 rounded-xl p-6 md:p-8 mb-4">
        <div className="flex justify-end mb-2">
          <div className="flex items-center gap-5 text-sm text-steel-600">
            <span className="flex items-center gap-2">PE only <span className="w-2.5 h-2.5 rounded-full" style={{background:"#3d6b6e"}} /></span>
            <span className="flex items-center gap-2">SE only <span className="w-2.5 h-2.5 rounded-full" style={{background:"#c4703c"}} /></span>
            <span className="flex items-center gap-2">PE &amp; SE <span className="w-2.5 h-2.5 rounded-full" style={{background:"#2d5254"}} /></span>
          </div>
        </div>

        <div className="relative">
          <svg viewBox="0 0 220 125" className="w-full h-auto" style={{maxHeight:"440px", overflow:"hidden"}}>
            {/* Mainland (all states except AK, HI), translated so the content fills the viewBox */}
            <g transform={`translate(${MAINLAND_DX} ${MAINLAND_DY})`}>
              {mainlandAbbrs.map(a => renderPath(a))}
            </g>
            {/* Alaska inset, scaled down */}
            <g transform={`translate(${AK_DX} ${AK_DY}) scale(${AK_SCALE})`}>
              {renderPath("AK")}
            </g>
            {/* Hawaii inset */}
            <g transform={`translate(${HI_DX} ${HI_DY})`}>
              {renderPath("HI")}
            </g>
            {tooltipName && tooltipCenter && (
              <g style={{ pointerEvents: "none" }}>
                <rect x={tooltipCenter[0] - tooltipName.length * 1.8} y={tooltipCenter[1] - 11} width={Math.max(tooltipName.length * 3.6, 24)} height="9" rx="1.5" fill="white" stroke="#c4c0ba" strokeWidth="0.4" />
                <text x={tooltipCenter[0]} y={tooltipCenter[1] - 5} textAnchor="middle" fontSize="5" fontWeight="500" fill="#37302f" fontFamily="Inter,system-ui,sans-serif">{tooltipName}</text>
              </g>
            )}
          </svg>
          {lt("VI") !== "none" && (
            <div
              className={`absolute bottom-4 right-4 rounded-lg px-3 py-2 text-xs cursor-pointer transition-colors border ${active==="VI"?"bg-primary-700 text-white border-primary-700":"bg-primary-600 text-white border-primary-600 hover:bg-primary-700"}`}
              onMouseEnter={() => setHovered("VI")}
              onMouseLeave={() => setHovered(null)}
              onClick={() => setSelected(p=>p==="VI"?null:"VI")}
            >
              <div className="font-bold">USVI</div>
              <div className="text-white/70 text-[10px]">Near Puerto Rico</div>
            </div>
          )}
        </div>
        <p className="text-steel-500 text-xs mt-3">Illustration of U.S. states with professional registration; the jurisdiction list is the authoritative record.</p>
      </div>

      <h3 className="text-primary-500 font-bold text-xl mb-1">Licensed jurisdictions</h3>
      <p className="text-steel-500 text-sm mb-6">Select a jurisdiction to keep it highlighted on the map. Click again to clear.</p>

      <div className="bg-white rounded-xl border border-gray-200 p-6 md:p-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {[
            { title: "PE ONLY", names: peOnlyNames, badge: "bg-primary-500" },
            { title: "SE ONLY", names: seOnlyNames, badge: "bg-accent-500" },
            { title: "PE & SE", names: peSeNames, badge: "bg-steel-700" },
          ].filter(c => c.names.length > 0).map(({ title, names, badge }) => (
            <div key={title}>
              <div className="flex items-center justify-between mb-4">
                <h4 className="text-sm font-bold text-accent-500 tracking-wide">{title}</h4>
                <span className={`w-7 h-7 rounded-full ${badge} text-white text-xs font-bold flex items-center justify-center`}>{names.length}</span>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {names.map(name => (
                  <button
                    key={name}
                    className={`text-left text-sm py-2 px-3 rounded-md border transition-all cursor-pointer ${isActive(name)?"bg-primary-500 text-white border-primary-500":"text-steel-600 border-gray-200 hover:border-primary-300 hover:bg-primary-50"}`}
                    onMouseEnter={() => handleHoverName(name)}
                    onMouseLeave={handleLeaveName}
                    onClick={() => handleClickName(name)}
                  >{name}</button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
